  1	import * as React from 'react';
  2	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  3	import { getNamespace } from '@odf/shared';
  4	import { EfficiencyItemBody } from '@odf/shared/dashboards/storage-efficiency/storage-efficiency-card-item';
  5	import {
  6	  useCustomPrometheusPoll,
  7	  usePrometheusBasePath,
  8	} from '@odf/shared/hooks/custom-prometheus-poll';
  9	import { OverviewDetailItem as DetailItem } from '@odf/shared/overview-page';
 10	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 11	import {
 12	  getInstantVectorStats,
 13	  humanizeBinaryBytes,
 14	  humanizePercentage,
 15	  getGaugeValue,
 16	} from '@odf/shared/utils';
 17	import {
 18	  Card,
 19	  CardBody,
 20	  CardHeader,
 21	  CardTitle,
 22	  DescriptionList,
 23	} from '@patternfly/react-core';
 24	import { getPoolQuery, StorageDashboardQuery } from '../../queries';
 25	import { PoolMetrics } from '../../types';
 26	import { getPerPoolMetrics } from '../../utils';
 27	import { BlockPoolDashboardContext } from './block-pool-dashboard-context';
 28	
 29	export const CompressionDetailsCard: React.FC = () => {
 30	  const { t } = useCustomTranslation();
 31	  const { obj } = React.useContext(BlockPoolDashboardContext);
 32	
 33	  const clusterNs = getNamespace(obj as any);
 34	  const { systemFlags } = useODFSystemFlagsSelector();
 35	  const managedByOCS = systemFlags[clusterNs]?.ocsClusterName;
 36	
 37	  const compressionMode = obj.spec?.compressionMode;
 38	  const compressionEnabled = !!compressionMode && compressionMode !== 'none';
 39	  const { name } = obj.metadata;
 40	
 41	  const queries = React.useMemo(
 42	    () => [
 43	      getPoolQuery(
 44	        [name],
 45	        StorageDashboardQuery.POOL_COMPRESSION_SAVINGS,
 46	        managedByOCS
 47	      ),
 48	      getPoolQuery(
 49	        [name],
 50	        StorageDashboardQuery.POOL_COMPRESSION_ELIGIBILITY,
 51	        managedByOCS
 52	      ),
 53	      getPoolQuery(
 54	        [name],
 55	        StorageDashboardQuery.POOL_COMPRESSION_RATIO,
 56	        managedByOCS
 57	      ),
 58	    ],
 59	    [name, managedByOCS]
 60	  );
 61	
 62	  const [poolCompressionSavings, savingsError, savingsLoading] =
 63	    useCustomPrometheusPoll({
 64	      query: queries[0],
 65	      endpoint: 'api/v1/query' as any,
 66	      basePath: usePrometheusBasePath(),
 67	    });
 68	  const compressionSavings: PoolMetrics = getPerPoolMetrics(
 69	    poolCompressionSavings,
 70	    savingsError,
 71	    savingsLoading
 72	  );
 73	
 74	  const [poolCompressionEligibility, eligibilityError, eligibilityLoading] =
 75	    useCustomPrometheusPoll({
 76	      query: queries[1],
 77	      endpoint: 'api/v1/query' as any,
 78	      basePath: usePrometheusBasePath(),
 79	    });
 80	  const compressionEligibility: PoolMetrics = getPerPoolMetrics(
 81	    poolCompressionEligibility,
 82	    eligibilityError,
 83	    eligibilityLoading
 84	  );
 85	
 86	  const [poolCompressionRatio, ratioError, ratioLoading] =
 87	    useCustomPrometheusPoll({
 88	      query: queries[2],
 89	      endpoint: 'api/v1/query' as any,
 90	      basePath: usePrometheusBasePath(),
 91	    });
 92	  const compressionRatio = getGaugeValue(poolCompressionRatio);
 93	  const capacityRatio = Number(compressionRatio);
 94	
 95	  const compressionEligibilityProps = {
 96	    stats: Number(getInstantVectorStats(poolCompressionEligibility)),
 97	    isLoading: eligibilityLoading,
 98	    error: eligibilityError || !poolCompressionEligibility,
 99	    title: t('Compression eligibility'),
100	    getStats: () => humanizePercentage(compressionEligibility?.[name])?.string,
101	    infoText: t(
102	      'Compression eligibility indicates the percentage of incoming data that is compressible'
103	    ),
104	  };
105	  const compressionSavingsProps = {
106	    stats: Number(getInstantVectorStats(poolCompressionSavings)),
107	    isLoading: savingsLoading,
108	    error: savingsError || !poolCompressionSavings,
109	    title: t('Compression savings'),
110	    getStats: () => humanizeBinaryBytes(compressionSavings?.[name])?.string,
111	    infoText: t(
112	      'Compression savings indicates the total savings gained from compression for this pool, including replicas'
113	    ),
114	  };
115	
116	  const compressionRatioProps = {
117	    stats: Number(compressionRatio),
118	    isLoading: ratioLoading,
119	    error: ratioError || !capacityRatio,
120	    title: t('Compression ratio'),
121	    getStats: () =>
122	      t('{{capacityRatio, number}}:1', {
123	        capacityRatio: Math.round(capacityRatio),
124	      }),
125	    infoText: t(
126	      'Compression ratio indicates the achieved compression on eligible data for this pool'
127	    ),
128	  };
129	
130	  const loading = ratioLoading || savingsLoading || eligibilityLoading;
131	
132	  return (
133	    <Card data-test-id="compression-details-card">
134	      <CardHeader>
135	        <CardTitle>{t('Compression')}</CardTitle>
136	      </CardHeader>
137	      <CardBody>
138	        <DescriptionList>
139	          <DetailItem isLoading={!obj} title={t('Compression status')}>
140	            {!compressionEnabled ? t('Disabled') : t('Enabled')}
141	          </DetailItem>
142	        </DescriptionList>
143	        {compressionEnabled && (
144	          <DescriptionList>
145	            <div>
146	              <DescriptionList>
147	                <DetailItem isLoading={loading} title={t('Storage efficiency')}>
148	                  <EfficiencyItemBody {...compressionEligibilityProps} />
149	                  <EfficiencyItemBody {...compressionRatioProps} />
150	                  <EfficiencyItemBody {...compressionSavingsProps} />
151	                </DetailItem>
152	              </DescriptionList>
153	            </div>
154	          </DescriptionList>
155	        )}
156	      </CardBody>
157	    </Card>
158	  );
159	};

