 1	import * as React from 'react';
 2	import {
 3	  DescriptionListDescription,
 4	  DescriptionListGroup,
 5	  DescriptionListTerm,
 6	} from '@patternfly/react-core';
 7	
 8	import './OverviewDetailItem.scss';
 9	
10	export type OverviewDetailItemProps = {
11	  /** Details card title */
12	  title: string;
13	  children: React.ReactNode;
14	  /** Trigger skeleton loading component during the loading phase. */
15	  isLoading?: boolean;
16	  /** Value for a className */
17	  valueClassName?: string;
18	  /** Error message to display */
19	  error?: string;
20	};
21	
22	/**
23	 * A wrapper around PatternFly's description group. This component's parent must
24	 * be a PatternFly DescriptionList.
25	 */
26	export const OverviewDetailItem: React.FC<OverviewDetailItemProps> = ({
27	  title,
28	  isLoading = false,
29	  children,
30	  error,
31	  valueClassName,
32	}) => {
33	  let status: React.ReactNode;
34	
35	  if (error) {
36	    status = (
37	      <span className="odf-overview-details-card__text-secondary">{error}</span>
38	    );
39	  } else if (isLoading) {
40	    status = <div className="odf-overview-details-card__skeleton-text" />;
41	  } else {
42	    status = children;
43	  }
44	  return (
45	    <DescriptionListGroup>
46	      <DescriptionListTerm data-test="detail-item-title">
47	        {title}
48	      </DescriptionListTerm>
49	      <DescriptionListDescription
50	        className={valueClassName}
51	        data-test="detail-item-value"
52	      >
53	        {status}
54	      </DescriptionListDescription>
55	    </DescriptionListGroup>
56	  );
57	};

