 89	      endpoint: 'api/v1/query' as any,
 90	      basePath: usePrometheusBasePath(),
 91	    });
 92	  const compressionRatio = getGaugeValue(poolCompressionRatio);
 93	  const capacityRatio = Number(compressionRatio);
 94	
 95	  const compressionEligibilityProps = {
 96	    stats: Number(getInstantVectorStats(poolCompressionEligibility)),
 97	    isLoading: eligibilityLoading,
 98	    error: eligibilityError || !poolCompressionEligibility,
 99	    title: t('Compression eligibility'),
100	    getStats: () => humanizePercentage(compressionEligibility?.[name])?.string,
101	    infoText: t(
102	      'Compression eligibility indicates the percentage of incoming data that is compressible'
103	    ),
104	  };
105	  const compressionSavingsProps = {
106	    stats: Number(getInstantVectorStats(poolCompressionSavings)),
107	    isLoading: savingsLoading,
108	    error: savingsError || !poolCompressionSavings,
109	    title: t('Compression savings'),
110	    getStats: () => humanizeBinaryBytes(compressionSavings?.[name])?.string,
111	    infoText: t(
112	      'Compression savings indicates the total savings gained from compression for this pool, including replicas'
113	    ),
114	  };
115	
116	  const compressionRatioProps = {
117	    stats: Number(compressionRatio),
118	    isLoading: ratioLoading,
119	    error: ratioError || !capacityRatio,
120	    title: t('Compression ratio'),
121	    getStats: () =>
122	      t('{{capacityRatio, number}}:1', {
123	        capacityRatio: Math.round(capacityRatio),
124	      }),
125	    infoText: t(
126	      'Compression ratio indicates the achieved compression on eligible data for this pool'
127	    ),
128	  };
129	
130	  const loading = ratioLoading || savingsLoading || eligibilityLoading;
131	
132	  return (
133	    <Card data-test-id="compression-details-card">
134	      <CardHeader>
135	        <CardTitle>{t('Compression')}</CardTitle>
136	      </CardHeader>
137	      <CardBody>
138	        <DescriptionList>
139	          <DetailItem isLoading={!obj} title={t('Compression status')}>
140	            {!compressionEnabled ? t('Disabled') : t('Enabled')}
141	          </DetailItem>
142	        </DescriptionList>
143	        {compressionEnabled && (
144	          <DescriptionList>
145	            <DetailItem isLoading={loading} title={t('Storage efficiency')}>
146	              <EfficiencyItemBody {...compressionEligibilityProps} />
147	              <EfficiencyItemBody {...compressionRatioProps} />
148	              <EfficiencyItemBody {...compressionSavingsProps} />
149	            </DetailItem>
150	          </DescriptionList>
151	        )}
152	      </CardBody>
153	    </Card>
154	  );
155	};
